- 'young hopefuls' refers to applicants under 30 years old;
- 'larger loans than the typical allowance' refers to loan requests higher than the average approved loan amount;
- 'basic info' includes gender, age, education, and employment status.

sql:
SELECT residence_id, TANH(rent_amount) AS tanh_rent_amount
FROM residences
WHERE residence_type = 'house';

SELECT marital_status, AVG(age) AS average_age, COUNT(applicant_id) AS applicant_count
FROM applicants
GROUP BY marital_status;

external_knowledge:
- "Voyagers" refers to the applicants;
- "Financial threshold" metaphorically represents the approval status of a loan application;
- "Land of approved loans" signifies the condition where the loan application status is 'approved';
- "Treasures and burdens" include financial information like net income, monthly expenses, and any collateral offered;
- "Maps of their journeys" encompass the application dates, decision dates, and disbursal dates.

sql:
SELECT DISTINCT applicants.email, applicants.phone_number
FROM applicants
JOIN loans ON applicants.applicant_id = loans.applicant_id;

SELECT SUM(approved_amount) AS total_approved_amount
FROM loan_status
WHERE status = 'approved';

SELECT applicant_id
FROM applicants
WHERE age > 50 AND employ_status = 'full_time';

SELECT COUNT(DISTINCT l.applicant_id)
FROM loans l
JOIN financials f ON l.applicant_id = f.applicant_id
WHERE f.net_income > (
    SELECT AVG(net_income) FROM financials
);

SELECT age
FROM applicants
WHERE applicant_id = 0;

SELECT status, decision_date 
FROM loan_status 
WHERE status_id = 1;
